import Foundation

/// En Dash brand palette — colour tokens shared across the app layer zones
/// (settings-ui, overlay-ui, and any future ui zones).
///
/// Living in GoToBedCore makes these definitions accessible without any
/// cross-zone import: both the settings editor and the overlay can reference
/// BrandColor and AppearancePreset via the foundation layer they already import.
public enum BrandColor: String, CaseIterable {
    case pink, orange, green, teal, darkBlue, purple, darkGray, black, white

    public var label: String {
        switch self {
        case .pink: return "n-pink"
        case .orange: return "n-orange"
        case .green: return "n-green"
        case .teal: return "n-teal"
        case .darkBlue: return "n-darkblue"
        case .purple: return "n-purple"
        case .darkGray: return "n-darkgray"
        case .black: return "n-black"
        case .white: return "n-white"
        }
    }

    public var hex: String {
        switch self {
        case .pink: return "D52E66"
        case .orange: return "FF5926"
        case .green: return "00BD81"
        case .teal: return "00E5B9"
        case .darkBlue: return "001769"
        case .purple: return "6C41F0"
        case .darkGray: return "4B5462"
        case .black: return "000000"
        case .white: return "FFFFFF"
        }
    }

    public var components: ColorComponents { ColorComponents(hex: hex) }
}

public extension ColorComponents {
    /// Parse "#RRGGBB" / "RRGGBB" (alpha defaults to opaque).
    init(hex: String) {
        var s = hex
        if s.hasPrefix("#") { s.removeFirst() }
        var v: UInt64 = 0
        Scanner(string: s).scanHexInt64(&v)
        self.init(
            red: Double((v >> 16) & 0xFF) / 255,
            green: Double((v >> 8) & 0xFF) / 255,
            blue: Double(v & 0xFF) / 255,
            alpha: 1
        )
    }

    /// True when RGB matches `other` (ignoring alpha), within a small tolerance.
    func matchesRGB(_ other: ColorComponents) -> Bool {
        let t = 0.004
        return abs(red - other.red) < t && abs(green - other.green) < t && abs(blue - other.blue) < t
    }
}

/// A curated background+text brand combination, applied in one tap.
public struct AppearancePreset: Identifiable {
    public let name: String
    public let background: BrandColor
    public let text: BrandColor
    public var id: String { name }

    public init(name: String, background: BrandColor, text: BrandColor) {
        self.name = name
        self.background = background
        self.text = text
    }

    /// Apply to an appearance, preserving the separately-controlled opacity and
    /// font sizes — only the colors change.
    public func apply(to appearance: inout AppearanceSettings) {
        var bg = background.components
        bg.alpha = appearance.backgroundColor.alpha
        appearance.backgroundColor = bg
        appearance.textColor = text.components
    }

    /// All curated combos are high-contrast (pass the readability threshold).
    public static let all: [AppearancePreset] = [
        AppearancePreset(name: "Midnight", background: .darkBlue, text: .white),
        AppearancePreset(name: "Teal Night", background: .black, text: .teal),
        AppearancePreset(name: "Sunset", background: .darkBlue, text: .orange),
        AppearancePreset(name: "Berry", background: .black, text: .pink),
        AppearancePreset(name: "Aurora", background: .darkBlue, text: .teal),
        AppearancePreset(name: "Violet", background: .purple, text: .white),
        AppearancePreset(name: "Slate", background: .darkGray, text: .white),
        AppearancePreset(name: "Mono", background: .black, text: .white),
    ]
}

import SwiftUI
import GoToBedCore

// BrandColor, ColorComponents hex extension, and AppearancePreset live in
// GoToBedCore/Models/Palette.swift so both settings-ui and any future overlay-ui
// zone can reference shared visual tokens without a cross-zone import.

/// A row of tappable preset chips, each previewing its background + text combo.
struct PresetRow: View {
    @Binding var appearance: AppearanceSettings

    var body: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 8) {
                ForEach(AppearancePreset.all) { preset in
                    Button { preset.apply(to: &appearance) } label: {
                        VStack(spacing: 3) {
                            ZStack {
                                RoundedRectangle(cornerRadius: 6)
                                    .fill(Color(preset.background.components))
                                Text("Aa")
                                    .font(.system(.caption, design: .rounded).weight(.semibold))
                                    .foregroundStyle(Color(preset.text.components))
                            }
                            .frame(width: 46, height: 30)
                            .overlay(RoundedRectangle(cornerRadius: 6).stroke(.secondary.opacity(0.3)))
                            Text(preset.name)
                                .font(.caption2)
                                .foregroundStyle(.secondary)
                        }
                    }
                    .buttonStyle(.plain)
                    .help("\(preset.name): \(preset.text.label) on \(preset.background.label)")
                    .accessibilityLabel("\(preset.name) preset")
                }
            }
            .padding(.vertical, 2)
        }
    }
}

/// A row of brand-color swatches that set the bound color on tap.
struct SwatchPicker: View {
    @Binding var color: ColorComponents
    /// Keep the current alpha (used for the background, whose opacity is set
    /// separately). When false the swatch's opaque alpha is applied.
    var preserveAlpha: Bool

    var body: some View {
        HStack(spacing: 6) {
            ForEach(BrandColor.allCases, id: \.self) { brand in
                let c = brand.components
                let selected = color.matchesRGB(c)
                Button {
                    var newColor = c
                    if preserveAlpha { newColor.alpha = color.alpha }
                    color = newColor
                } label: {
                    Circle()
                        .fill(Color(ColorComponents(red: c.red, green: c.green, blue: c.blue, alpha: 1)))
                        .frame(width: 20, height: 20)
                        .overlay(Circle().stroke(.secondary.opacity(0.35)))
                        .overlay(
                            Circle()
                                .stroke(Color.accentColor, lineWidth: selected ? 2.5 : 0)
                                .padding(-2)
                        )
                }
                .buttonStyle(.plain)
                .help("\(brand.label) (#\(brand.hex))")
                .accessibilityLabel(brand.label)
                .accessibilityAddTraits(selected ? .isSelected : [])
            }
        }
    }
}

import AppKit
import SwiftUI
import GoToBedCore

/// Manages the settings/editor window directly via AppKit.
///
/// A menu-bar-only (accessory) app cannot reliably open the SwiftUI `Settings`
/// scene through the `showSettingsWindow:` action selector, so we own a normal
/// `NSWindow` hosting `SettingsView` and bring it forward on demand. While it is
/// open the app is `.regular` (so it can take focus and show in the Dock); it
/// returns to `.accessory` on close unless an overlay is up.
///
/// This file lives alongside AppEnvironment.swift (the composition root) rather
/// than inside UI/ because window lifecycle is a composition-root concern:
/// AppEnvironment decides when to present or dismiss the window, and all
/// windowing decisions flow through it.
@MainActor
final class SettingsWindowController: NSObject, NSWindowDelegate {
    private var window: NSWindow?
    private let env: AppEnvironment

    init(env: AppEnvironment) {
        self.env = env
    }

    func show() {
        _ = NSApp.setActivationPolicy(.regular)
        NSApp.activate(ignoringOtherApps: true)

        if let window {
            window.makeKeyAndOrderFront(nil)
            return
        }

        let root = SettingsView()
            .environmentObject(env)
            .environmentObject(env.store)
            .frame(minWidth: 760, minHeight: 560)

        let window = NSWindow(
            contentRect: NSRect(x: 0, y: 0, width: 900, height: 640),
            styleMask: [.titled, .closable, .resizable, .miniaturizable],
            backing: .buffered,
            defer: false
        )
        window.title = "GoToBed"
        window.contentView = NSHostingView(rootView: root)
        window.isReleasedWhenClosed = false
        window.delegate = self
        window.center()
        window.makeKeyAndOrderFront(nil)
        self.window = window
        Log.lifecycle.info("Opened settings window.")
    }

    func windowWillClose(_ notification: Notification) {
        // Restore menu-bar-only state when settings closes (unless an overlay is
        // currently showing and already manages the policy).
        if !env.overlay.isShowing {
            _ = NSApp.setActivationPolicy(.accessory)
        }
    }
}

import Foundation

/// Pre-computed display data for a single schedule in the menu-bar popover.
///
/// Produced by `AppEnvironment.scheduleItems` and passed into `MenuContent` as
/// a plain value, so the menu view has no direct dependency on `Store` or
/// `Schedule`. All domain reads are resolved at the composition root.
struct ScheduleDisplayItem: Identifiable {
    let id: UUID
    let timeString: String
    /// "Mon–Fri · Time to wind down" style summary.
    let subtitle: String
    let isEnabled: Bool
}

import AppKit
import Combine
import GoToBedCore

/// Composition root: wires the Store -> SchedulerEngine -> OverlayController
/// graph and exposes high-level actions (preview, launch-at-login) to the UI.
///
/// All write operations on the domain model (Store mutations) flow through
/// coordinator methods on this class so settings-ui views hold no direct write
/// dependency on Store — only AppEnvironment decides when and how the model
/// changes.
@MainActor
public final class AppEnvironment: ObservableObject {
    public static let shared = AppEnvironment()

    public let store: Store
    let scheduler: SchedulerEngine
    let overlay: OverlayController

    /// Lazily created so it can reference `self` (the env) for window hosting.
    private(set) lazy var settingsWindow = SettingsWindowController(env: self)

    /// Relay Store mutations to env.objectWillChange so views that observe only
    /// this object (e.g. MenuContent) still rebuild when schedules change.
    private var storeCancellable: AnyCancellable?

    private init() {
        store = Store()
        overlay = OverlayController()
        scheduler = SchedulerEngine(store: store)

        scheduler.onFire = { [overlay] schedule in
            overlay.present(schedule)
        }

        storeCancellable = store.objectWillChange.sink { [weak self] _ in
            self?.objectWillChange.send()
        }
    }

    // MARK: Window management

    /// Open the settings/editor window (managed directly via AppKit).
    public func openSettings() {
        settingsWindow.show()
    }

    // MARK: Schedule coordinator (write proxy for settings-ui)

    /// Build (but do not insert) a new schedule seeded from the current default
    /// appearance, so the editor opens pre-populated (FR-15).
    func makeSchedule(
        hour: Int,
        minute: Int,
        weekdays: Set<Int>,
        message: String,
        dismissMode: DismissMode = .auto(seconds: DismissMode.defaultAutoSeconds)
    ) -> Schedule {
        store.makeSchedule(
            hour: hour, minute: minute, weekdays: weekdays,
            message: message, dismissMode: dismissMode
        )
    }

    /// Insert a schedule. Invalid schedules are coerced into range first.
    @discardableResult
    func addSchedule(_ schedule: Schedule) -> Schedule {
        store.add(schedule)
    }

    /// Replace an existing schedule (matched by id) with an updated, sanitized copy.
    func updateSchedule(_ schedule: Schedule) {
        store.update(schedule)
    }

    /// Delete a schedule by id.
    func deleteSchedule(id: UUID) {
        store.delete(id: id)
    }

    /// Toggle the enabled state of a schedule.
    func setScheduleEnabled(_ enabled: Bool, id: UUID) {
        store.setEnabled(enabled, id: id)
    }

    /// Update the app-wide default appearance.
    func updateDefaultAppearance(_ appearance: AppearanceSettings) {
        store.updateDefaultAppearance(appearance)
    }

    // MARK: Menu-bar view model

    /// Pre-computed display items for the menu-bar popover.
    ///
    /// MenuContent reads this instead of observing Store directly, so the menu
    /// view has no direct domain dependency.
    var scheduleItems: [ScheduleDisplayItem] {
        store.schedules.map { schedule in
            ScheduleDisplayItem(
                id: schedule.id,
                timeString: ScheduleFormatting.timeString(schedule),
                subtitle: ScheduleFormatting.daysAndMessage(schedule),
                isEnabled: schedule.isEnabled
            )
        }
    }

    // MARK: Misc actions

    /// Offline-preserving update check: open the latest releases page in the
    /// default browser. Handing off a URL needs no network entitlement, so the
    /// app's zero-network guarantee (NFR-priv-1) is preserved.
    func checkForUpdates() {
        NSWorkspace.shared.open(AppInfo.releasesURL)
    }

    /// Add a new schedule seeded from defaults, then open the editor to it.
    func addScheduleAndEdit() {
        store.add(store.makeSchedule(
            hour: 22, minute: 30, weekdays: WeekdayPreset.everyDay,
            message: "Time to wind down. Go to bed."
        ))
        openSettings()
    }

    /// Begin scheduling. Called once from the app delegate after launch.
    public func start() {
        scheduler.start()
        Log.lifecycle.info("GoToBed started with \(self.store.schedules.count, privacy: .public) schedule(s).")
    }

    /// Tear down scheduling and any visible overlay (FR-21: quitting stops all
    /// scheduling, no daemon persists).
    public func shutdown() {
        scheduler.stop()
        overlay.dismiss()
    }

    /// Show `schedule`'s overlay immediately, without affecting scheduling
    /// (PRD "preview overlay" action). Falls back to the first schedule.
    func previewOverlay(_ schedule: Schedule? = nil) {
        let target = schedule ?? store.schedules.first ?? Schedule(
            hour: 0, minute: 0, weekdays: WeekdayPreset.everyDay,
            message: "Preview", appearance: store.defaultAppearance
        )
        overlay.present(target)
    }

    // MARK: Launch at login

    var launchAtLoginEnabled: Bool { LaunchAtLogin.isEnabled }

    func setLaunchAtLogin(_ enabled: Bool) {
        do {
            try LaunchAtLogin.set(enabled)
            store.setLaunchAtLogin(enabled)
        } catch {
            Log.lifecycle.error("Failed to set launch at login: \(String(describing: error), privacy: .public)")
        }
    }
}

import SwiftUI
import GoToBedCore

/// The menu-bar popover: quick-toggle list of schedules plus the primary
/// actions (PRD §6, FR-19).
///
/// MenuContent reads only from `AppEnvironment` (the composition root) and
/// never touches `Store` directly. Domain data arrives pre-computed as
/// `[ScheduleDisplayItem]` via `env.scheduleItems`, so this view has no
/// direct domain dependency.
public struct MenuContent: View {
    public init() {}

    @EnvironmentObject private var env: AppEnvironment

    public var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Text("GoToBed").font(.headline)
                Spacer()
                Text("v\(AppInfo.version)")
                    .font(.caption2).foregroundStyle(.secondary)
                    .accessibilityLabel("Version \(AppInfo.version)")
            }

            if env.scheduleItems.isEmpty {
                Text("No schedules yet.")
                    .foregroundStyle(.secondary)
                    .padding(.vertical, 4)
            } else {
                ForEach(env.scheduleItems) { item in
                    ScheduleRow(item: item) { enabled in
                        env.setScheduleEnabled(enabled, id: item.id)
                    }
                }
            }

            Divider()

            Button("Add Schedule…") { env.addScheduleAndEdit() }
            Button("Settings…") { env.openSettings() }
            Button("Preview Overlay") { env.previewOverlay() }

            Toggle("Launch at Login", isOn: Binding(
                get: { env.launchAtLoginEnabled },
                set: { env.setLaunchAtLogin($0) }
            ))
            .toggleStyle(.checkbox)

            Divider()
            Button("Check for Updates…") { env.checkForUpdates() }
            Button("Quit GoToBed") { NSApp.terminate(nil) }
                .keyboardShortcut("q")
        }
        .padding(12)
        .frame(width: 280)
    }
}

/// A single schedule row with an inline enable toggle. Disabled schedules are
/// dimmed to read as visually distinct (FR-5).
///
/// Receives a `ScheduleDisplayItem` (plain value) and an `onToggle` callback
/// rather than observing Store directly.
private struct ScheduleRow: View {
    let item: ScheduleDisplayItem
    let onToggle: (Bool) -> Void

    var body: some View {
        HStack {
            Toggle("", isOn: Binding(
                get: { item.isEnabled },
                set: { onToggle($0) }
            ))
            .labelsHidden()
            .toggleStyle(.switch)
            .controlSize(.mini)

            VStack(alignment: .leading, spacing: 1) {
                Text(item.timeString)
                    .font(.system(.body, design: .rounded))
                    .monospacedDigit()
                Text(item.subtitle)
                    .font(.caption)
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
            }
            Spacer()
        }
        .opacity(item.isEnabled ? 1 : 0.45)
        .accessibilityElement(children: .combine)
        .accessibilityLabel("\(item.timeString), \(item.isEnabled ? "enabled" : "disabled")")
    }
}

import SwiftUI
import GoToBedCore

/// Editor for a single schedule. Edits a local draft and writes sanitized
/// changes back through AppEnvironment (the composition root).
///
/// Writing through `env.updateSchedule(_:)` rather than `store.update(_:)` keeps
/// the settings-ui zone free of direct Store write dependencies (PRD §3.1, §6).
struct ScheduleEditorView: View {
    @EnvironmentObject private var env: AppEnvironment

    @State private var draft: Schedule
    /// Remembered auto duration so toggling Manual -> Auto restores the value.
    @State private var autoSeconds: Int

    init(schedule: Schedule) {
        _draft = State(initialValue: schedule)
        _autoSeconds = State(initialValue: schedule.dismissMode.autoSeconds ?? DismissMode.defaultAutoSeconds)
    }

    var body: some View {
        Form {
            Section {
                Toggle("Enabled", isOn: $draft.isEnabled)
                DatePicker("Time", selection: timeBinding, displayedComponents: .hourAndMinute)
            }

            Section("Active days") {
                WeekdayPicker(weekdays: $draft.weekdays)
                if draft.weekdays.isEmpty {
                    Label("Select at least one day.", systemImage: "exclamationmark.triangle")
                        .font(.caption).foregroundStyle(.orange)
                }
            }

            Section("Message") {
                VStack(alignment: .leading, spacing: 4) {
                    Text("Primary").font(.caption).foregroundStyle(.secondary)
                    TextEditor(text: $draft.message)
                        .frame(minHeight: 54)
                        .font(.body)
                    Text("\(draft.message.count)/\(Schedule.maxMessageLength)")
                        .font(.caption2).foregroundStyle(.secondary)
                        .frame(maxWidth: .infinity, alignment: .trailing)
                }
                VStack(alignment: .leading, spacing: 4) {
                    Text("Submessage (optional)").font(.caption).foregroundStyle(.secondary)
                    TextEditor(text: $draft.submessage)
                        .frame(minHeight: 40)
                        .font(.body)
                    Text("\(draft.submessage.count)/\(Schedule.maxMessageLength)")
                        .font(.caption2).foregroundStyle(.secondary)
                        .frame(maxWidth: .infinity, alignment: .trailing)
                }
            }

            Section("Dismissal") {
                Picker("When shown", selection: isAutoBinding) {
                    Text("Auto-dismiss").tag(true)
                    Text("Manual (Esc)").tag(false)
                }
                .pickerStyle(.segmented)

                if draft.dismissMode.autoSeconds != nil {
                    Stepper(value: autoSecondsBinding, in: Schedule.durationRange, step: 5) {
                        Text("Duration: \(autoSeconds)s")
                    }
                }
            }

            Section("Appearance") {
                AppearanceEditor(appearance: $draft.appearance)
            }

            Section {
                Button("Preview Overlay") { env.previewOverlay(draft) }
            }
        }
        .formStyle(.grouped)
        // Persist (sanitized) on any change through the composition-root coordinator.
        .onChangeCompat(of: draft) { newValue in env.updateSchedule(newValue) }
    }

    // MARK: Bindings

    private var timeBinding: Binding<Date> {
        Binding(
            get: {
                var c = DateComponents(); c.hour = draft.hour; c.minute = draft.minute
                return Calendar.current.date(from: c) ?? Date()
            },
            set: { newDate in
                let c = Calendar.current.dateComponents([.hour, .minute], from: newDate)
                draft.hour = c.hour ?? draft.hour
                draft.minute = c.minute ?? draft.minute
            }
        )
    }

    private var isAutoBinding: Binding<Bool> {
        Binding(
            get: { draft.dismissMode.autoSeconds != nil },
            set: { isAuto in
                draft.dismissMode = isAuto ? .auto(seconds: autoSeconds) : .manual
            }
        )
    }

    private var autoSecondsBinding: Binding<Int> {
        Binding(
            get: { autoSeconds },
            set: { newValue in
                autoSeconds = newValue
                draft.dismissMode = .auto(seconds: newValue)
            }
        )
    }
}

import SwiftUI
import GoToBedCore

/// The settings window: a Schedules tab (list + editor) and a Default
/// Appearance tab (PRD §6).
struct SettingsView: View {
    var body: some View {
        TabView {
            SchedulesPane()
                .tabItem { Label("Schedules", systemImage: "list.bullet") }
            DefaultAppearancePane()
                .tabItem { Label("Default Appearance", systemImage: "paintpalette") }
        }
        .padding()
    }
}

/// Master/detail: schedule list on the left, editor on the right.
///
/// Domain reads come from `store` (for reactive SwiftUI updates); domain
/// writes are routed through `env` coordinator methods so this view holds no
/// direct Store write dependency.
private struct SchedulesPane: View {
    @EnvironmentObject private var env: AppEnvironment
    @EnvironmentObject private var store: Store
    @State private var selection: UUID?

    var body: some View {
        HSplitView {
            VStack(spacing: 0) {
                List(selection: $selection) {
                    ForEach(store.schedules) { schedule in
                        VStack(alignment: .leading) {
                            Text(ScheduleFormatting.timeString(schedule))
                                .monospacedDigit()
                                .opacity(schedule.isEnabled ? 1 : 0.45)
                            Text(ScheduleFormatting.daysSummary(schedule.weekdays))
                                .font(.caption).foregroundStyle(.secondary)
                        }
                        .tag(schedule.id)
                    }
                }
                HStack {
                    Button(action: addSchedule) { Image(systemName: "plus") }
                        .help("Add schedule")
                    Button(action: deleteSelected) { Image(systemName: "minus") }
                        .help("Delete schedule")
                        .disabled(selection == nil)
                    Spacer()
                }
                .padding(6)
            }
            .frame(minWidth: 220)

            Group {
                if let id = selection, let schedule = store.schedule(id: id) {
                    ScheduleEditorView(schedule: schedule)
                        .id(id)
                } else {
                    Text("Select or add a schedule")
                        .foregroundStyle(.secondary)
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                }
            }
            .frame(minWidth: 500)
        }
    }

    private func addSchedule() {
        let new = env.makeSchedule(
            hour: 22, minute: 30, weekdays: WeekdayPreset.everyDay,
            message: "Time to wind down. Go to bed."
        )
        env.addSchedule(new)
        selection = new.id
    }

    private func deleteSelected() {
        guard let id = selection else { return }
        env.deleteSchedule(id: id)
        selection = store.schedules.first?.id
    }
}

/// Default appearance editor: edits a local draft and persists through the
/// composition-root coordinator on change.
private struct DefaultAppearancePane: View {
    @EnvironmentObject private var env: AppEnvironment
    @EnvironmentObject private var store: Store
    @State private var draft: AppearanceSettings = .appDefault

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("New schedules start from these settings. Editing them does not change existing schedules.")
                .font(.callout)
                .foregroundStyle(.secondary)
            AppearanceEditor(appearance: $draft)
            Spacer()
        }
        .onAppear { draft = store.defaultAppearance }
        .onChangeCompat(of: draft) { new in env.updateDefaultAppearance(new) }
    }
}
